#!/usr/bin/env bash
# Deploy the /vantaca query form + recommended-action cards to the Slack bot.
#
# WHAT THIS CHANGES (index.mjs, digest.mjs, vantaca-claude.mjs):
#   QUERY FORM (replaces the quick menu):
#     - /vantaca (no text) or "/vantaca menu" opens a MODAL: pick Manager
#       (optional, defaults to all 6), a view (All open / Newest / Urgent /
#       Aged 30d+ / Overdue / Water intrusion / Parked on the manager), and an
#       optional Association filter (typeahead). Submit -> one filtered result set.
#     - Queue views merge the selected manager(s) via vantaca_managerQueue,
#       dedupe by XN, filter by view + association client-side (from reasons/
#       ageDays/dueDate/priorityScore). The "Aged" view uses vantaca_agedWorkOrders
#       (assocCode passthrough). All cached (queue ~10m, aged ~5m) -> no AI tokens.
#   EVERY XN CARD now shows a *Recommended:* next action (derived from the
#     priority signals already on the item — no extra API/AI call) AND an
#     Advance ▸ button. Advance opens the modal that computes the exact next
#     workflow step + editable note on click (authoritative path for the write).
#     This applies to the morning digest cards too (itemCard gained the line).
#   COST/CACHE: mcpTools() sorts tools by name so the prompt cache (tools+system)
#     stays byte-stable; free-text (/vantaca <q>, @mentions, DMs) still uses askVantaca.
#
#   No new Slack scopes — Socket Mode already delivers view_submission,
#   block_actions, and block_suggestion (external_select options).
#
# Backs up all four .mjs (timestamped .bak), writes them, node --check each,
# then `systemctl restart vantaca-slack`. Safe to re-run.
#
# REQUIREMENTS (not present in the Claude-Code-on-web sandbox):
#   - ssh client + ~/.ssh/vantaca_vps private key, egress to 134.209.126.217:22
#
cd /root/vantaca-mcp/slack-bot && ts=$(date +%s) && for f in index.mjs vantaca-claude.mjs daily-report.mjs digest.mjs; do { [ -f "$f" ] && cp "$f" "$f.bak.$ts"; } || true; done && printf %s "" | base64 -d > index.mjs && printf %s "" | base64 -d > vantaca-claude.mjs && printf %s "" | base64 -d > daily-report.mjs && printf %s "" | base64 -d > digest.mjs && node --check index.mjs && node --check vantaca-claude.mjs && node --check daily-report.mjs && node --check digest.mjs && echo SYNTAX_OK && systemctl restart vantaca-slack && sleep 2 && echo "slack:$(systemctl is-active vantaca-slack)"
